const B = 32; // branching factor
const SHIFT = 5; // log2(B)
const MASK = B - 1;

/** Node of the bit‑mapped trie.  Either a leaf (values) or an internal node (children). */
class Node<T> {
    constructor(
        public readonly cnt: number,
        public readonly children?: Node<T>[],
        public readonly vals?: T[]
    ) {}

    isLeaf(): boolean {
        return this.vals !== undefined;
    }
}

/**
