export class PersistentVector<T> {
    private readonly _root: Node<T> | null;
    private readonly _size: number;
    private readonly _tail: T[];
    private readonly _shift: number; // shift for the root’s children

    constructor(
        root?: Node<T> | null,
        size?: number,
        tail?: T[],
        shift?: number
