// ParseQuery takes a URL‑query string literal and returns the corresponding object type.
// It works entirely at compile time using template‑literal types and recursion.
export type ParseQuery<S extends string> =
  // If there is another key=value pair after an '&', split it out and recurse on the rest.
  S extends `${infer Key}=${infer Value}&${infer Rest}`
    ? { [K in Key]: Value } & ParseQuery<Rest>
    // Otherwise, if there's a single key=value (no '&'), create that entry.
    : S extends `${infer Key}=${infer Value}`
      ? { [K in Key]: Value }
      // Empty string → empty object.
      : {};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private _listeners: { [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void> } = {};

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const existing = this._listeners[name];
    if (existing) {
      existing.push(handler);
    } else {
      this._listeners[name] = [handler];
    }
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this._listeners[name];
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

export class MedianStream {
  private maxHeap: Heap<number>;
  private minHeap: Heap<number>;

  constructor() {
    // Max‑heap for the lower half (largest element at root)
    this.maxHeap = new Heap<number>((a, b) => b - a);
    // Min‑heap for the upper half (smallest element at root)
    this.minHeap = new Heap<number>((a, b) => a - b);
  }

  add(n: number): void {
    if (this.maxHeap.size() === 0 || n <= this.maxHeap.peek()) {
      this.maxHeap.insert(n);
    } else {
      this.minHeap.insert(n);
    }
    // Rebalance so that maxHeap size = minHeap size or maxHeap size = minHeap size + 1
    if (this.maxHeap.size() > this.minHeap.size() + 1) {
      const moved = this.maxHeap.extractTop();
      this.minHeap.insert(moved);
    } else if (this.minHeap.size() > this.maxHeap.size()) {
      const moved = this.minHeap.extractTop();
      this.maxHeap.insert(moved);
    }
  }

  median(): number {
    if (this.maxHeap.size() === 0) {
      throw new Error('MedianStream empty');
    }
    if (this.maxHeap.size() > this.minHeap.size()) {
      // Odd number of elements – the median is the root of maxHeap
      return this.maxHeap.peek();
    } else {
      // Even number of elements – average the two middle values
      const lower = this.maxHeap.peek(); // largest in lower half
      const upper = this.minHeap.peek(); // smallest in upper half
      return (lower + upper) / 2;
    }
  }
}

/** Generic binary heap implementation */
class Heap<T> {
  private data: T[] = [];
  private compare: (a: T, b: T) => number;

  constructor(comp: (a: T, b: T) => number) {
    this.compare = comp;
  }

  size(): number {
    return this.data.length;
  }

  peek(): T {
    if (this.data.length === 0) throw new Error('Heap empty');
    return this.data[0];
  }

  insert(item: T): void {
    this.data.push(item);
    this.bubbleUp(this.data.length - 1);
  }

  extractTop(): T {
    const top = this.peek();
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      this.bubbleDown(0);
    }
    return top;
  }

  private bubbleUp(idx: number): void {
    while (idx > 0) {
      const parentIdx = Math.floor((idx - 1) / 2);
      if (this.compare(this.data[idx], this.data[parentIdx]) < 0) {
        [this.data[idx], this.data[parentIdx]] = [this.data[parentIdx], this.data[idx]];
        idx = parentIdx;
      } else {
        break;
      }
    }
  }

  private bubbleDown(idx: number): void {
    const length = this.data.length;
    while (true) {
      const leftChild = 2 * idx + 1;
      const rightChild = 2 * idx + 2;
      let smallest = idx;

      if (leftChild < length && this.compare(this.data[leftChild], this.data[smallest]) < 0) {
        smallest = leftChild;
      }
      if (rightChild < length && this.compare(this.data[rightChild], this.data[smallest]) < 0) {
        smallest = rightChild;
      }

      if (smallest !== idx) {
        [this.data[idx], this.data[smallest]] = [this.data[smallest], this.data[idx]];
        idx = smallest;
      } else {
        break;
      }
    }
  }
}
